CREATE TABLE IF NOT EXISTS `dixi_name_mappings` (
  `id` int AUTO_INCREMENT NOT NULL,
  `companyId` int NOT NULL,
  `dixiName` varchar(255) NOT NULL,
  `dixiId` varchar(50),
  `employeeId` int NOT NULL,
  `employeeName` varchar(255) NOT NULL,
  `source` enum('manual','import_link') NOT NULL DEFAULT 'manual',
  `createdBy` varchar(255),
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `dixi_name_mappings_id` PRIMARY KEY(`id`)
);

CREATE INDEX `dnm_company` ON `dixi_name_mappings` (`companyId`);
CREATE INDEX `dnm_dixi_name` ON `dixi_name_mappings` (`companyId`, `dixiName`);
CREATE INDEX `dnm_employee` ON `dixi_name_mappings` (`employeeId`);
